### 2. Schema-per-Tenant (Strong Isolation, Moderate Scale)

```sql
-- Tenant provisioning script
CREATE OR REPLACE FUNCTION create_tenant_schema(tenant_slug TEXT)
RETURNS void AS $$
BEGIN
  -- Create isolated schema
  EXECUTE format('CREATE SCHEMA tenant_%s', tenant_slug);

  -- Create all tables in that schema
  EXECUTE format('
    CREATE TABLE tenant_%s.organizations (
      id        UUID PRIMARY KEY DEFAULT gen_random_uuid(),
      name      TEXT NOT NULL,
      created_at TIMESTAMPTZ DEFAULT NOW()
    )', tenant_slug);

  -- Grant permissions to app user
  EXECUTE format(
    'GRANT USAGE ON SCHEMA tenant_%s TO app_user', 
    tenant_slug
  );
  EXECUTE format(
    'GRANT ALL ON ALL TABLES IN SCHEMA tenant_%s TO app_user', 
    tenant_slug
  );
END;
$$ LANGUAGE plpgsql;

-- Usage
SELECT create_tenant_schema('acme_corp');
SELECT create_tenant_schema('globex');
```

